;&lt;/span&gt;false&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;enableDeleteByExample&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;false&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;enableSelectByExample&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;false&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;enableUpdateByExample&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;false&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;38&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;table&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;tableName&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;company&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;domainObjectName&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;Company&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;enableCountByExample&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;false&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;enableDeleteByExample&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;false&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;enableSelectByExample&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;false&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;enableUpdateByExample&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;false&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;39&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;context&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;40&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;generatorConfiguration&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;运行插件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#运行插件&#34;&gt;#&lt;/a&gt; 运行插件&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;https://gitee.com/sakuralee/blog-img/raw/master/img/20210714101740.png&#34; alt=&#34;image-20210714101740593&#34; /&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://gitee.com/sakuralee/blog-img/raw/master/img/20210714102048.png&#34; alt=&#34;image-20210714102048120&#34; /&gt;&lt;/p&gt;

 &lt;h1 id=&#34;kafka安装&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#kafka安装&#34;&gt;#&lt;/a&gt; Kafka 安装&lt;/h1&gt;
&lt;p&gt;&lt;strong&gt;我是使用的阿里云 centos7 进行的安装模拟&lt;/strong&gt;&lt;/p&gt;
&lt;h2 id=&#34;单机版&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#单机版&#34;&gt;#&lt;/a&gt; 单机版&lt;/h2&gt;
&lt;h3 id=&#34;首先需要安装zookeeper&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#首先需要安装zookeeper&#34;&gt;#&lt;/a&gt; 首先需要安装 zookeeper&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;wget https://mirrors.bfsu.edu.cn/apache/zookeeper/zookeeper-3.6.3/apache-zookeeper-3.6.3-bin.tar.gz
tar -zxvf apache-zookeeper-3.6.3-bin.tar.gz
cd apache-zookeeper-3.6.3-bin
# 启动 zookeeper
bin/zkServer.sh start
bin/zkCli.sh
# 查看zk的根目录相关节点
ls /
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://gitee.com/sakuralee/blog-img/raw/master/img/20210623201307.png&#34; alt=&#34;image-20210623201307807&#34; /&gt;&lt;/p&gt;
&lt;p&gt;我这边启动报错说是找不到配置文件，因为默认的配置文件根本就不叫这个名... 我佛了，在  &lt;code&gt;conf&lt;/code&gt;  目录下复制一份配置文件并命名为  &lt;code&gt;cp zoo_sample.cfg zoo.cfg&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://gitee.com/sakuralee/blog-img/raw/master/img/20210623201821.png&#34; alt=&#34;image-20210623201821493&#34; /&gt;&lt;/p&gt;
&lt;p&gt;zookeeper 启动成功&lt;/p&gt;
&lt;h3 id=&#34;安装kafka&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装kafka&#34;&gt;#&lt;/a&gt; 安装 Kafka&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;# 下载并解压
wget https://mirrors.tuna.tsinghua.edu.cn/apache/kafka/2.8.0/kafka_2.12-2.8.0.tgz
tar -zxvf kafka_2.12-2.8.0.tgz
cd kafka_2.12-2.8.0

# 启动
bin/kafka-server-start.sh -daemon config/server.properties

# 在 zookeeper 下查看
ls /
# 查看 kafka 节点
ls /brokers/ids

&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://gitee.com/sakuralee/blog-img/raw/master/img/20210623202454.png&#34; alt=&#34;image-20210623202454724&#34; /&gt;&lt;/p&gt;
&lt;h2 id=&#34;集群版&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#集群版&#34;&gt;#&lt;/a&gt; 集群版&lt;/h2&gt;
&lt;p&gt;参考：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9rYWZrYS5hcGFjaGVjbi5vcmcvcXVpY2tzdGFydC5odG1s&#34;&gt;kafka 中文文档&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;下载并解压 kafka&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;wget https://mirrors.bfsu.edu.cn/apache/kafka/2.8.0/kafka_2.12-2.8.0.tgz
tar -zxvf kafka_2.12-2.8.0.tgz
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;img data-src=&#34;https://gitee.com/sakuralee/blog-img/raw/master/img/20210626141533.png&#34; alt=&#34;image-20210626141526377&#34; /&gt;&lt;/p&gt;
&lt;p&gt;复制两份 kafka 的配置文件&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;cp config/server.properties config/server-1.properties
cp config/server.properties config/server-2.properties
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;编辑这两份配置文件以及原本的配置文件&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;config/server.properties:
    broker.id=0
    listeners=PLAINTEXT://:9092
    log.dir=/tmp/kafka-logs-0

config/server-1.properties:
    broker.id=1
    listeners=PLAINTEXT://:9093
    log.dir=/tmp/kafka-logs-1

config/server-2.properties:
    broker.id=2
    listeners=PLAINTEXT://:9094
    log.dir=/tmp/kafka-logs-2
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;启动 zookeeper&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;bin/zookeeper-server-start.sh config/zookeeper.properties
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;启动 kafka 集群&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;gt; bin/kafka-server-start.sh config/server.properties
&amp;gt; bin/kafka-server-start.sh config/server-1.properties 
&amp;gt; bin/kafka-server-start.sh config/server-2.properties
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;创建一个副本为 3 的  topic&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;bin/kafka-topics.sh --create --zookeeper localhost:2181 --replication-factor 3 --partitions 1 --topic my-replicated-topic
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;查看集群中 topic 信息&lt;/p&gt;
&lt;p&gt;&lt;code&gt;bin /kafka-topics.sh --describe --zookeeper localhost:2181 --topic my-replicated-topic&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://gitee.com/sakuralee/blog-img/raw/master/img/20210626151135.png&#34; alt=&#34;image-20210626151135659&#34; /&gt;&lt;/p&gt;
&lt;h1 id=&#34;消息引擎模型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#消息引擎模型&#34;&gt;#&lt;/a&gt; 消息引擎模型&lt;/h1&gt;
&lt;h2 id=&#34;点对点模型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#点对点模型&#34;&gt;#&lt;/a&gt; 点对点模型&lt;/h2&gt;
&lt;p&gt;点对点模型是基于队列提供消息传输服务的，该模型定义了消息队列、发送者和接收者，提供了一种点对点的消息传递方式，即发送者发送每条消息到队列的指定位置，接收者从指定位置获取消息，一旦消息被消费，就会从队列中移除该消息。每条消息由一个发送者生产出来，且只被一个消费者消费，发送者和消费者之间是一对一的关系。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://gitee.com/sakuralee/blog-img/raw/master/img/20210623203319.png&#34; alt=&#34;image-20210623203319585&#34; /&gt;&lt;/p&gt;
&lt;h2 id=&#34;发布订阅模型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#发布订阅模型&#34;&gt;#&lt;/a&gt; 发布 / 订阅模型&lt;/h2&gt;
&lt;p&gt;发布 / 订阅模型有主题（Topic）的概念。这种模型也定义了类似于生产者 / 消费者这样的角色，即发布者和订阅者，发布者将消息生产出来发送到指定的 topic 中，所有订阅了该 topic 的订阅者都可以接收到该 topic 下的所有信息，通常具有相同订阅 topic 的所有订阅者将接收到同样的消息。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://gitee.com/sakuralee/blog-img/raw/master/img/20210623203703.png&#34; alt=&#34;image-20210623203703222&#34; /&gt;&lt;/p&gt;
&lt;h1 id=&#34;基本概念&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#基本概念&#34;&gt;#&lt;/a&gt; 基本概念&lt;/h1&gt;
&lt;h2 id=&#34;消息&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#消息&#34;&gt;#&lt;/a&gt; 消息&lt;/h2&gt;
&lt;p&gt;消息指的是 Kafka 处理的主要对象&lt;/p&gt;
&lt;h2 id=&#34;broker&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#broker&#34;&gt;#&lt;/a&gt; Broker&lt;/h2&gt;
&lt;p&gt;broker 是指一个 kafka 服务器。如果多个 broker 形成集群会依靠 zookeeper 集群进行服务的协调管理。&lt;/p&gt;
&lt;p&gt;生产者发送消息给 kafka 服务器，消费者从 kafka 服务器读取消息。&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;&lt;/p&gt;
&lt;h2 id=&#34;topic和partition&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#topic和partition&#34;&gt;#&lt;/a&gt; Topic 和 Partition&lt;/h2&gt;
&lt;p&gt;topic 代表了一类消息，也可以认为是消息被发送到的地方。通常我们可以使用 topic 来区分实际业务，比如业务 A 使用一个 topic，业务 B 使用另一个 topic。&lt;/p&gt;
&lt;p&gt;kafka 中的 topic 通常都会被多个消费者订阅，因此处于性能的考量，kafka 并不是 topic-message 的两级结构，而是采用 topic-partition-message 的三级结构来分散负载。&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://gitee.com/sakuralee/blog-img/raw/master/img/20210623223222.png&#34; alt=&#34;image-20210623223222857&#34; /&gt;&lt;/p&gt;
&lt;p&gt;如图，topic 是由多个 partition 组成的，而 kafka 的 partition 是不可修改的有序消息队列，也可以说是有序的消息日志。每个 partition 有自己专属的 partition 号，通常是从 0 开始。用户对 partition 唯一能做的操作就是在消息序列的尾部追加写入消息。partition 上的每条消息都会被分配一个唯一的序列号，该序列号被称为位移。&lt;/p&gt;
&lt;h2 id=&#34;生产者和消费者&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#生产者和消费者&#34;&gt;#&lt;/a&gt; 生产者和消费者&lt;/h2&gt;
&lt;p&gt;向 topic 发布消息的客户端应用程序称为生产者，生产者程序通常持续不断地向一个或多个 topic 发送消息，而订阅这些 topic 消息的客户端应用程序就被称为消费者。和生产者类似，消费者也能够同时订阅多个 topic 的消息。&lt;/p&gt;
&lt;h2 id=&#34;消费者组&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#消费者组&#34;&gt;#&lt;/a&gt; 消费者组&lt;/h2&gt;
&lt;p&gt;Consumer Group 是指组里面有多个消费者或消费者实例，它们共享一个公共的 ID，这个 ID 被称为 Group ID。组内所有消费者协调在一起来消费订阅 topic 的所有 partition，当然，每个分区只能由同一个消费者组内的一个 Consumer 实例来消费。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;三个特性&lt;/strong&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;消费者组下可以有一个或多个 Consumer 实例；&lt;/li&gt;
&lt;li&gt;Group ID 是一个字符串，在一个 kafka 集群中，它标识唯一的一个 Consumer Group；&lt;/li&gt;
&lt;li&gt;Consumer Group 下所有实例订阅的 topic 的单个分区，只能分配给组内某个 Consumer 实例消费。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;两种消息模型实现&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;如果所有实例都属于同一个 gruop，那么就是实现了&lt;strong&gt;点对点模型&lt;/strong&gt;；如果所有实例分别属于不同的 gruop，那么就实现了&lt;strong&gt;订阅 / 发布模型。&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;在实际使用场景中，一个 gruop 该有多少个 consumer 实例？&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;理想情况下，consumer 实例的数量应该等于该 gruop 订阅 topic 的分区总数。&lt;/p&gt;
&lt;p&gt;举一个简单的例子，如果一个 consumer gruop 订阅了 3 个 topic，分别是 A、B、C，它们的分区数依次是 1,2,3，那么通常情况下，为该 gruop 设置 6 个 consumer 实例是比较理想的情形，因为它能最大限度地实现高伸缩性。&lt;/p&gt;
&lt;h3 id=&#34;消费顺序问题&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#消费顺序问题&#34;&gt;#&lt;/a&gt; 消费顺序问题&lt;/h3&gt;
&lt;p&gt;按照上面的设计，可能导致消费顺序问题&lt;/p&gt;
&lt;h4 id=&#34;乱序场景一&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#乱序场景一&#34;&gt;#&lt;/a&gt; 乱序场景一&lt;/h4&gt;
&lt;p&gt;因为一个 topic 可以有多个 partition，kafka 只能保证 partition 内部有序，当 partition 数量 = 同一个消费者组中消费者数量时，可能需要顺序的数据分布到了不同的 partition，导致处理时乱序。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;解决方案&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;可以设置 topic 有且只有一个 partition；&lt;/li&gt;
&lt;li&gt;根据业务需要，需要顺序的消息放在同一个 partition；&lt;/li&gt;
&lt;/ol&gt;
&lt;h4 id=&#34;乱序场景二&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#乱序场景二&#34;&gt;#&lt;/a&gt; 乱序场景二&lt;/h4&gt;
&lt;p&gt;对于统一业务进入消费者组之后，用了多线程来处理消息，会导致消息的乱序。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;解决方案&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;消费者内部根据线程数量创建等量的内存队列，对于需要顺序的一系列业务数据，根据 key 或者业务数据，放到同一个内存队列中，然后线程从对应的内存队列中取出并操作。&lt;/p&gt;
&lt;h2 id=&#34;rebalance&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#rebalance&#34;&gt;#&lt;/a&gt; Rebalance&lt;/h2&gt;
&lt;p&gt;Rebalance 本质上是一个协议，规定了一个 consumer gruop 下的所有 consumer 如何达成一致，来分配订阅 topic 的每个分区。比如某个 gruop 下有 20 个 consumer 实例，它订阅了一个具有 100 个分区的 topic，正常情况下，kafka 平均会为每个 consumer 分配 5 个分区。这个分配的过程就叫 Rebalance。&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;Rebalance 触发的条件&lt;/strong&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;消费者组成员数发生变更；&lt;/li&gt;
&lt;li&gt;订阅 topic 发生变更；&lt;/li&gt;
&lt;li&gt;订阅 topic 分区数发生变更。&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;Rebalance 过程对消费者组消费过程有极大影响，会 stop the world。在 STW 期间，所有应用线程都会停止工作，表现为整个应用程序僵在那边一动不动。&lt;/p&gt;
&lt;h2 id=&#34;replica&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#replica&#34;&gt;#&lt;/a&gt; Replica&lt;/h2&gt;
&lt;p&gt;既然我们已知 partition 是有序消息日志，那么一定不能只保存这一份日志，否则一旦保存 partition 的 kafka 服务器挂掉了，其上保存的消息也就都丢失了。分布式系统必然要实现高可靠性，而目前实现的主要途径还是依靠冗余机制，通过备份多份日志。这些备份日志在 kafka 中称为 副本（replica），它们存在的唯一目的就是防止数据丢失。&lt;/p&gt;
&lt;h3 id=&#34;副本的分类&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#副本的分类&#34;&gt;#&lt;/a&gt; 副本的分类&lt;/h3&gt;
&lt;p&gt;** 追随者副本（follower replica）&lt;strong&gt;是不能提供服务给客户端的，也就是说不负责响应客户端发来的消息写入和消息消费请求，它只是被动地向&lt;/strong&gt;领导者副本（leader replica）** 获取数据，而一旦领导者副本所在的 broker 宕机，kafka 会从剩余的 replica 中选举出新的 leader 继续提供服务。&lt;/p&gt;
&lt;h3 id=&#34;leader和follower&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#leader和follower&#34;&gt;#&lt;/a&gt; leader 和 follower&lt;/h3&gt;
&lt;p&gt;&lt;img data-src=&#34;https://gitee.com/sakuralee/blog-img/raw/master/img/20210624163425.png&#34; alt=&#34;IMG_20210624_163406&#34; /&gt;&lt;/p&gt;
&lt;h2 id=&#34;isr&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#isr&#34;&gt;#&lt;/a&gt; ISR&lt;/h2&gt;
&lt;p&gt;ISR 的全称是 in-sync replica，翻译过来就是与 leader replica 保持同步的 replica 集合。&lt;/p&gt;
&lt;p&gt;kafka 为 partition 动态维护一个 replica 集合。该集合中的所有 replica 保存的消息日志都与 leader replica 保持同步状态。只有这个集合中的 replica 才能被选举为 leader，也只有该集合中所有 replica 都接收了同一条消息，kafka 才会将该消息置于 “已提交” 状态，即认为这条消息发送成功。&lt;/p&gt;
&lt;p&gt;如果因为各种各样的原因，一部分 replica 开始落后于 leader replica 的进度，当滞后到一定程度时，kafka 会将这些 replica 踢出 ISR，当这些 replica 重新追上了 leader 的进度时，那么 kafka 会将它们加回到 ISR 中。这一切都是自动维护的，不需要用户进行人工干预。&lt;/p&gt;
&lt;h1 id=&#34;使用场景&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#使用场景&#34;&gt;#&lt;/a&gt; 使用场景&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;日志收集&lt;/strong&gt;：一个公司可以用 kafka 收集各种服务的 log，通过 kafka 以统一接口服务的方式开放给各种 consumer，例如 Hadoop、HBASE、solr 等；&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;消息系统&lt;/strong&gt;：解耦生产者、消费者、缓存消息等；&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;用户活动追踪&lt;/strong&gt;：kafka 经常被用来记录 web 用户或者 app 用户的各种活动，如浏览网页、搜索、点击等活动，这些活动信息被各服务器发布到 kafka 的 topic 中，然后订阅者通过订阅这些 topic 来做实时的监控分析，或者装载到 hadoop、数据仓库中做离线分析和挖掘；&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;运营指标&lt;/strong&gt;：kafka 也经常用来记录运营监控数据。包括收集各种分布式应用的数据，生产各种操作的集中反馈，比如报警和报告。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;kafka为什么快&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#kafka为什么快&#34;&gt;#&lt;/a&gt; kafka 为什么快&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;顺序读写&lt;/strong&gt;：kafka 的消息是不断追加到文件中的，这个特性使 kafka 可以充分利用磁盘的顺序读写功能，顺序读写不需要硬盘磁头的寻道时间，只需很少的扇区旋转时间，所以速度远快于随机读写。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;零拷贝&lt;/strong&gt;：零拷贝是直接从&lt;strong&gt;内核空间到内核空间再到网卡&lt;/strong&gt;，而普通拷贝是&lt;strong&gt;内核到用户再到内核再到网卡&lt;/strong&gt;，省去了用户空间的复制。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;分区&lt;/strong&gt;：kafka 的 topic 中的内容可以被分为多份 partition 存在，每个 partition 又分为多个段 segment，所以每次操作都是针对一小部分做操作，很轻便，并且增加了&lt;strong&gt;并行操作&lt;/strong&gt; 的能力。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;批量发送&lt;/strong&gt;：kafka 允许进行批量发送消息，producer 发送消息的时候，可以将消息缓存在本地，等到了固定条件再发送到 kafka。固定条件一般有：1. 等消息条数达到固定条数；2. 一段时间发送一次。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;数据压缩&lt;/strong&gt;：kafka 还支持对消息集合进行压缩，producer 可以通过 gzip 或 snappy 格式对消息集合进行压缩。压缩的好处就是减少传输的数据量，减轻对网络传输的压力。producer 压缩之后，在 consumer 需要解压，虽然增加了 cpu 的工作，但是在大数据处理上，瓶颈在网络上而不是 cpu，所以这个成本很值。&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;实际应用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#实际应用&#34;&gt;#&lt;/a&gt; 实际应用&lt;/h1&gt;
&lt;p&gt;我 kafka 和 zookeeper 是使用本地 win 下的环境，因为我连不上阿里云的，明明端口都开放了...&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L2dpdGh1Yl8zODQ4MjA4Mi9hcnRpY2xlL2RldGFpbHMvODIxMTI2NDE=&#34;&gt;win10 下单机 kafka 安装教程&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;验证是否安装成功我是使用的 idea 中的 zookeeper、kafka 监测插件 Zoolytic-Zookeeper tool、Kafkalytic&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://gitee.com/sakuralee/blog-img/raw/master/img/20210625102050.png&#34; alt=&#34;image-20210625102050057&#34; /&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://gitee.com/sakuralee/blog-img/raw/master/img/20210625102338.png&#34; alt=&#34;image-20210625102338786&#34; /&gt;&lt;/p&gt;
&lt;h2 id=&#34;java应用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#java应用&#34;&gt;#&lt;/a&gt; Java 应用&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;引入依赖&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight xml&#34;&gt;&lt;figcaption data-lang=&#34;XML&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;dependency&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;groupId&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;org.apache.kafka&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;groupId&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;artifactId&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;kafka-clients&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;artifactId&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;version&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;2.8.0&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;version&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;dependency&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;新建配置类&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;figcaption data-lang=&#34;java&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;KafkaConstants&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;final&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt; BROKER_LIST &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;localhost:9092&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;final&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt; CLIENT_ID &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;client1&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Group_ID_CONFIG&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;consumerGroup1&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;private&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;KafkaConstants&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;定义生产者和消费者&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight java&#34;&gt;&lt;figcaption data-lang=&#34;java&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;class&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;ProducerCreator&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;public&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;static&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Producer&lt;/span&gt;&lt;span class=&#34;token generics&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;createProducer&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token class-name&#34;&gt;Properties&lt;/span&gt; properties &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;new&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Properties&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&